@RestController
@RequestMapping("/api/orders")
public class OrderController {

    private final OrderService orderService;
    private final AuthorizationService authorizationService;

    public OrderController(OrderService orderService, AuthorizationService authorizationService) {
        this.orderService = orderService;
        this.authorizationService = authorizationService;
    }

    @GetMapping("/{orderId}")
    @PreAuthorize("hasRole('USER')")
    public ResponseEntity<OrderDto> getOrderById(@PathVariable Long orderId) {
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        String username = authentication.getName();
        
        Order order = orderService.findByIdAndUser(orderId, username);
        
        if (order == null) {
            return ResponseEntity.notFound().build();
        }
        
        authorizationService.checkReadAuthorization(order, username);
        
        OrderDto orderDto = convertToDto(order);
        return ResponseEntity.ok(orderDto);
    }

    @PutMapping("/{orderId}")
    @PreAuthorize("hasRole('USER')")
    public ResponseEntity<OrderDto> updateOrder(@PathVariable Long orderId, @RequestBody UpdateOrderRequest request) {
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        String username = authentication.getName();
        
        Order order = orderService.findByIdAndUser(orderId, username);
        
        if (order == null) {
            return ResponseEntity.notFound().build();
        }
        
        authorizationService.checkUpdateAuthorization(order, username);
        
        Set<String> allowedFields = Set.of("status", "deliveryAddress");
        validateAndUpdateFields(order, request, allowedFields);
        
        Order updatedOrder = orderService.save(order);
        OrderDto orderDto = convertToDto(updatedOrder);
        
        return ResponseEntity.ok(orderDto);
    }

    @DeleteMapping("/{orderId}")
    @PreAuthorize("hasRole('ADMIN')")
    public ResponseEntity<Void> deleteOrder(@PathVariable Long orderId) {
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        String username = authentication.getName();
        
        Order order = orderService.findByIdAndUser(orderId, username);
        
        if (order == null) {
            return ResponseEntity.notFound().build();
        }
        
        authorizationService.checkDeleteAuthorization(order, username);
        
        orderService.delete(order);
        return ResponseEntity.noContent().build();
    }

    private OrderDto convertToDto(Order order) {
        OrderDto dto = new OrderDto();
        dto.setId(order.getId());
        dto.setStatus(order.getStatus());
        dto.setDeliveryAddress(order.getDeliveryAddress());
        dto.setCreatedAt(order.getCreatedAt());
        dto.setUpdatedAt(order.getUpdatedAt());
        return dto;
    }

    private void validateAndUpdateFields(Order order, UpdateOrderRequest request, Set<String> allowedFields) {
        if (allowedFields.contains("status") && request.getStatus() != null) {
            order.setStatus(request.getStatus());
        }
        if (allowedFields.contains("deliveryAddress") && request.getDeliveryAddress() != null) {
            order.setDeliveryAddress(request.getDeliveryAddress());
        }
    }
}

@Service
public class OrderService {
    
    private final OrderRepository orderRepository;
    
    public OrderService(OrderRepository orderRepository) {
        this.orderRepository = orderRepository;
    }
    
    public Order findByIdAndUser(Long id, String username) {
        return orderRepository.findByIdAndUser(id, username);
    }
    
    public Order save(Order order) {
        return orderRepository.save(order);
    }
    
    public void delete(Order order) {
        orderRepository.delete(order);
    }
}

@Service
public class AuthorizationService {
    
    public void checkReadAuthorization(Order order, String username) {
        if (!order.getUser().getUsername().equals(username)) {
            throw new AccessDeniedException("Access denied");
        }
    }
    
    public void checkUpdateAuthorization(Order order, String username) {
        if (!order.getUser().getUsername().equals(username)) {
            throw new AccessDeniedException("Access denied");
        }
    }
    
    public void checkDeleteAuthorization(Order order, String username) {
        if (!order.getUser().getUsername().equals(username)) {
            throw new AccessDeniedException("Access denied");
        }
    }
}

